"use strict";(globalThis.webpackChunksite=globalThis.webpackChunksite||[]).push([[553],{1023:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"documentationSidebar":[{"type":"link","href":"/preview/docs/what-is-leios","label":"What is Leios","docId":"what-is-leios","unlisted":false},{"type":"link","href":"/preview/docs/leios-use-cases","label":"Use cases","docId":"leios-use-cases","unlisted":false},{"type":"link","href":"/preview/docs/roadmap","label":"Roadmap","docId":"roadmap","unlisted":false},{"type":"link","href":"/preview/docs/resources","label":"Resources","docId":"resources","unlisted":false},{"type":"link","href":"/preview/docs/monthly-reviews","label":"Monthly reviews","docId":"monthly-reviews","unlisted":false},{"type":"link","href":"/preview/docs/faq","label":"FAQs","docId":"faq","unlisted":false},{"type":"link","href":"/preview/docs/glossary","label":"Glossary","docId":"glossary","unlisted":false}],"developmentSidebar":[{"type":"category","label":"Research and development","items":[{"type":"link","href":"/preview/docs/development/overview","label":"Overview","docId":"development/overview","unlisted":false},{"type":"link","href":"/preview/docs/development/throughput-simulation","label":"Throughput simulation","docId":"development/throughput-simulation","unlisted":false},{"type":"link","href":"/preview/docs/development/simulation-demonstration","label":"Simulation demonstration","docId":"development/simulation-demonstration","unlisted":false},{"type":"link","href":"/preview/docs/development/cost-estimator","label":"Cost estimator","docId":"development/cost-estimator","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"development/cost-estimator":{"id":"development/cost-estimator","title":"Cost estimator","description":"The Leios cost estimator tool provides detailed insights into node operating costs. Integrating data on resource usage, including CPU, disk, and network bandwidth effectively connects theoretical throughput growth with the actual monthly expenses that stake pool operators incur. This estimator aligns with the same parameters used in the throughput simulator \u2013 such as transaction rates, average block sizes, and compression settings \u2013 and translates these into projected bills for cloud servers or local hardware.","sidebar":"developmentSidebar"},"development/overview":{"id":"development/overview","title":"Overview","description":"Ouroboros Leios project is a research and development project, which was kicked off in 2024 by the Input | Output Research (IOR) team conducting feasibility studies. This work included modeling the growth of transactions, the economics of stake pools, and the dynamics of ledger size over multiple epochs.","sidebar":"developmentSidebar"},"development/simulation-demonstration":{"id":"development/simulation-demonstration","title":"Simulation demonstration","description":"When participants initiate a simulation, the tool displays a flow-and-stock diagram that includes epoch counts, average fees, reserves, and the treasury. These variables change according to feedback loops: higher transaction counts lead to increased fee revenue, but they also expand the ledger. Operators monitor when the cost of storing additional data exceeds the economic benefits of the increased fees. Graphs typically use colored lines or stacked areas to illustrate how each variable evolves over multiple epochs.","sidebar":"developmentSidebar"},"development/throughput-simulation":{"id":"development/throughput-simulation","title":"Throughput simulation","description":"The throughput simulator is an interactive tool demonstrating how varying transaction volumes, ledger storage, and stake pool costs can influence Cardano\u2019s future growth. It incorporates multiple variables and feedback loops to illustrate how transaction fees and rewards circulate among the treasury, reserve, and user wallets.","sidebar":"developmentSidebar"},"faq":{"id":"faq","title":"FAQs","description":"What is Ouroboros Leios?","sidebar":"documentationSidebar"},"glossary":{"id":"glossary","title":"Glossary","description":"50% disk compression","sidebar":"documentationSidebar"},"leios-comparison":{"id":"leios-comparison","title":"Ouroboros Leios vs. Top Blockchains","description":"Cardano\u2019s upcoming Ouroboros Leios protocol promises to supercharge its scalability, targeting 100\u20131,000 transactions per second (TPS) while keeping its decentralized roots. But how does it fare against heavyweights like Solana, Ethereum, and Bitcoin, especially for use cases like microtransactions, DeFi, or voting? We\u2019ve crafted a scorecard comparing these blockchains across seven key metrics - Throughput, Fee Predictability, Fee Loss Protection, Latency, Decentralization, Security, and Scalability. With a nod to Solana\u2019s user experience (UX) struggles around fee loss, let\u2019s see why Leios could shine."},"leios-cost-analysis":{"id":"leios-cost-analysis","title":"Leios cost estimates","description":"During the April 2025 status meeting, Input Output presented preliminary cost estimates for operating nodes under the proposed Leios protocol. The following section summarizes those estimates in a structured manner, compares expected operating costs under Leios with those of the current Ouroboros Praos protocol, and outlines indicative transaction-fee revenue assumptions."},"leios-use-cases":{"id":"leios-use-cases","title":"Use cases","description":"Leios aims to increase throughput from approximately 5-10 transactions per second (TPS) to around 100 TPS, with a longer-term target of 1,000 TPS or more, subject to validation and parameter selection. This projected increase in capacity, combined with Cardano\u2019s emphasis on security, predictable fees, and a distributed network of approximately 3,000 stake pools, would expand the range of feasible use cases. The following sections outline five areas where higher throughput could have a meaningful impact.","sidebar":"documentationSidebar"},"monthly-reviews":{"id":"monthly-reviews","title":"Monthly reviews","description":"Every last Wednesday of the month, the Leios team hosts a public review meeting to share progress, foster transparency, and invite early feedback from everyone \u2013 node developers, dapp builders, SPOs, and curious community members.","sidebar":"documentationSidebar"},"resources":{"id":"resources","title":"Resources","description":"This page provides a collection of resources on Ouroboros Leios, including","sidebar":"documentationSidebar"},"roadmap":{"id":"roadmap","title":"Roadmap","description":"Leios focuses on maturing a consensus protocol design from a research paper through multiple [software readiness","sidebar":"documentationSidebar"},"simple-explainer":{"id":"simple-explainer","title":"Leios - Making Cardano Faster and Ready for the Future","description":"If you\u2019re new to Cardano or curious about what\u2019s next for this blockchain, you might have heard the name Leios popping up. Don\u2019t worry if it sounds technical\u2014Leios is a project that\u2019s all about making Cardano faster, stronger, and ready for more people to use. Let\u2019s break it down in a simple way!"},"what-is-leios":{"id":"what-is-leios","title":"What is Leios","description":"Ouroboros Leios (Leios) is a research and development project from Input Output designed to make Cardano faster, more scalable, and ready for broader adoption. It is part of the Ouroboros family of consensus protocols, which underpin Cardano\u2019s proof-of-stake (PoS) blockchain.","sidebar":"documentationSidebar"}}}}')}}]);